// frontend/src/App.js - FULLY CORRECTED
import React, { createContext, useState, useContext, useEffect, useCallback } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

// Import Your Components
import HomePage from './components/HomePage';
import Login from './components/Login';
import Signup from './components/Signup';
import HealthAssessment from './components/HealthAssessment';
import Dashboard from './components/Dashboard';
import MapPage from './components/MapPage';
import HealthReport from './components/HealthReport';
import FamilyPage from './components/FamilyPage';
import AdminDashboard from './components/AdminDashboard';
import AdminLogin from './components/AdminLogin';

// --- START: NEW ROBUST AUTHENTICATION LOGIC ---
const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true); // Start in a loading state

    // This function checks the server for an active session
    const checkUserSession = useCallback(async () => {
        try {
            const response = await fetch('/api/check-auth/'); // Calls the new Django API
            const data = await response.json();
            if (data.isAuthenticated) {
                setUser(data.user); // The server is the source of truth
            } else {
                setUser(null);
                localStorage.removeItem('user'); // Clean up old data
            }
        } catch (error) {
            console.error("Session check failed:", error);
            setUser(null);
        } finally {
            setLoading(false); // Authentication check is complete
        }
    }, []);

    useEffect(() => {
        checkUserSession(); // Check session on initial app load
    }, [checkUserSession]);

    const login = (userData) => {
        setUser(userData);
        // We can still keep this for immediate UI updates
        localStorage.setItem('user', JSON.stringify(userData));
    };

    const logout = async () => {
        await fetch('/api/logout/', { method: 'POST' }); // Tell backend to destroy session
        setUser(null);
        localStorage.removeItem('user');
        window.location.href = '/login'; // Redirect to login
    };

    const value = { user, loading, login, logout };

    return (
        <AuthContext.Provider value={value}>
            {loading ? <LoadingScreen /> : children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => {
    return useContext(AuthContext);
};
// --- END: NEW ROBUST AUTHENTICATION LOGIC ---


const ProtectedRoute = ({ children }) => {
    const { user, loading } = useAuth();
    if (loading) {
        return <LoadingScreen />;
    }
    return user ? children : <Navigate to="/login" replace />;
};

const AdminProtectedRoute = ({ children }) => {
    const adminUser = localStorage.getItem('admin_user');
    return adminUser ? children : <Navigate to="/admin/login" replace />;
};

const LoadingScreen = () => (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <p>Loading...</p>
    </div>
);

function App() {
  return (
    <AuthProvider>
      <Router>
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/login" element={<Login />} />
          <Route path="/signup" element={<Signup />} />
          <Route path="/map" element={<MapPage />} />

          <Route path="/dashboard" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
          <Route path="/health-assessment" element={<ProtectedRoute><HealthAssessment /></ProtectedRoute>} />
          <Route path="/health-report" element={<ProtectedRoute><HealthReport /></ProtectedRoute>} />
          <Route path="/add-family" element={<ProtectedRoute><FamilyPage /></ProtectedRoute>} />

          <Route path="/admin/login" element={<AdminLogin />} />
          <Route path="/admin/dashboard" element={<AdminProtectedRoute><AdminDashboard /></AdminProtectedRoute>} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}

export default App;
